// Minimal vulnerable replica of INVEscrow
contract INVEscrow {
    MockToken public token;
    MockXINV public xINV;
    address public market;
    uint256 public lastRecordedBalance;

    constructor(MockToken _token, MockXINV _xinv, address _market) {
        token = _token;
        xINV = _xinv;
        market = _market;
        lastRecordedBalance = 0;
    }

    // Vulnerable pay: developer intended to restrict everything to market
    // but mistakenly wrapped the guarded logic in an if-block, leaving the
    // final accounting update outside the guarded path. This allows any
    // caller to modify lastRecordedBalance.
    function pay(address recipient, uint256 amount) public {
        if (msg.sender == market) {
            uint256 invBalance = token.balanceOf(address(this));
            if (invBalance < amount) xINV.redeemUnderlying(amount - invBalance);
            token.transfer(recipient, amount);
        }
        // <-- This line is outside the guarded if-block and thus can be
        // executed by ANY caller, modifying internal accounting.
        lastRecordedBalance = token.balanceOf(address(this)) - amount;
    }
}

