        bool isCall;
        bool isLong;
        uint256[] floorTokens;
        uint256 premium;
        uint256 strike;
    }

    mapping(uint256 => address) public owners;
    mapping(bytes32 => bool) public cancelledOrders;
    mapping(uint256 => uint256) public positionExpirations;

