    function hashOrder(Order memory o) public pure returns (bytes32) {
        return keccak256(abi.encodePacked(o.maker, o.premium, o.isLong, o.isCall));
    }
    function hashOppositeOrder(Order memory o) public pure returns (bytes32) {
        return keccak256(abi.encodePacked(o.maker, o.premium, o.isLong, o.isCall, "opposite"));
    }
