        _mint(order.maker, uint256(orderHash));
        // create opposite position for taker
        bytes32 oppositeOrderHash = hashOppositeOrder(order);
        positionId = uint256(oppositeOrderHash);
        _mint(msg.sender, positionId);

        // transfer premium to whoever is short from whomever is long
        if (order.isLong) {
            MockERC20(order.baseAsset).safeTransferFrom(order.maker, msg.sender, order.premium);
        } else {
            // omitted: other branches not used in PoC
        }

        // filling long put: transfer strike from taker to contract
        if (order.isLong && !order.isCall) {
            if (order.strike > 0) {
                MockERC20(order.baseAsset).safeTransferFrom(msg.sender, address(this), order.strike);
            }
